async (params, browser) => {
  // Open Jira
  await browser.open(`${params.jira_url}/jira/software/projects`)

  // Let Jira load
  await browser.wait(2000)

  // Fetch sprint issues via Agile REST API
  const result = await browser.evaluate(`const baseUrl = params.jira_url.replace(/\/$/, ''); const resp = await fetch(baseUrl + '/rest/agile/1.0/sprint/' + params.sprint_id + '/issue?maxResults=50&fields=summary,status,assignee,priority,issuetype', { credentials: 'same-origin' }); if (!resp.ok) throw new Error('Sprint API error: ' + resp.status); const data = await resp.json(); const issues = (data.issues || []).map(i => ({ key: i.key, summary: i.fields.summary, status: i.fields.status?.name || '', assignee: i.fields.assignee?.displayName || 'Unassigned', priority: i.fields.priority?.name || '', type: i.fields.issuetype?.name || '' })); return { total: data.total || issues.length, result_count: issues.length, issues: issues }`)

  return result
}
